With.Cte:

				SELECT {{
							Fields
								-Dimension: PointsOfSale 
									--Table: PointsOfSaleCte
								-Dimension: Products 
									--Table: ProductsCte
								-Dimension: Calendar 
									--Table: CalendarCte
									--WithRequestedFields
								-WithComma
                		}}
                		[SalesAnalysis].[SalesQuantity], [SalesAnalysis].[SalesAmountTaxesIncluded], [SalesAnalysis].[SalesAmountTaxesExcluded]
                	FROM [Fact].[SalesAnalysis]
                	{{
                		InnerJoin 
                			-Dimension: PointsOfSale 
                				--Table: PointsOfSaleCte
							-Table: SalesAnalysis
							-On:PointOfSaleId-PointOfSaleId
                	}}
                	{{
                		InnerJoin 
                			-Dimension: Products 
                				--Table: ProductsCte
							-Table: SalesAnalysis
							-On: ProductId-ProductId
                	}}
                	{{
                		InnerJoin 
                			-Dimension: Calendar 
                				--Required
                				--Table: CalendarCte
							-Table: SalesAnalysis
							-On: Date-Date
                	}}
                	WHERE [SalesAnalysis].[Refund] = 0

With.Query:

				SELECT {{
							Fields
								-Dimension: PointsOfSale
								-Dimension: Products
								-Dimension: Calendar
									--WithRequestedFields
								-WithComma
                		}}
                		SUM(SalesQuantity) AS Quantity, SUM(SalesAmountTaxesIncluded) AS AmountTaxesIncluded, 
                		SUM(SalesAmountTaxesExcluded) AS AmountTaxesExcluded
                	FROM SalesCte
                	{{
						GroupBy
							-Dimension: PointsOfSale 
							-Dimension: Products
							-Dimension: Calendar
								--WithRequestedFields
                	}}
